import * as React from "react";
import styled from "styled-components";
import { whoWeAres } from "./data";
import { media } from "./media-queries";
import { useWindowSize } from "react-use";

// images as components
import ArrowLeft from "../images/arrow_left.svg";
import ArrowRight from "../images/arrow_right.svg";

export const Carousel = () => {
  const size = useWindowSize();
  const [leftActive, setLeftActive] = React.useState(false);
  const [rightActive, setRightActive] = React.useState(false);

  const listRef = React.useRef(null);

  const onWheel = React.useCallback(
    (e) => {
      const boxWidth =
        listRef?.current?.scrollWidth - listRef?.current?.offsetWidth;
      const scrollStep =
        size?.width > 1366
          ? listRef?.current?.offsetWidth / 4
          : listRef?.current?.offsetWidth / 2;
      const currentScrollLeft = listRef?.current?.scrollLeft;
      const delta = e.deltaY;

      if (
        (delta > 0 && currentScrollLeft < boxWidth) ||
        (delta < 0 && currentScrollLeft > 0)
      ) {
        e.preventDefault();
      }
      const blockSize = listRef?.current?.offsetWidth;

      listRef?.current?.scrollTo({
        top: 0,
        left: currentScrollLeft + Math.sign(e.deltaY) * scrollStep,
        behavior: "smooth",
      });
    },
    [size, size.width]
  );

  const onScroll = () => {
    const boxWidth =
      listRef?.current?.scrollWidth - listRef?.current?.offsetWidth;
    const currentScrollLeft = listRef?.current?.scrollLeft;
    setLeftActive(listRef?.current?.scrollLeft > 0);
    setRightActive(currentScrollLeft < boxWidth);
  };
  React.useEffect(() => {
    onScroll();
  }, [
    listRef?.current?.scrollWidth,
    listRef?.current?.offsetWidth,
    listRef?.current?.scrollLeft,
  ]);

  React.useEffect(() => {
    listRef?.current?.addEventListener("wheel", onWheel);
    return () => {
      listRef?.current?.removeEventListener("wheel", onWheel);
    };
  }, [listRef, listRef.current, onWheel]);

  const scrollLeftClick = () => {
    const currentScrollLeft = listRef?.current?.scrollLeft;
    const blockSize = listRef?.current?.offsetWidth;
    const scrollStep =
      size?.width > 1366
        ? listRef?.current?.offsetWidth / 4
        : listRef?.current?.offsetWidth / 2;
    listRef?.current?.scrollTo({
      top: 0,
      left: currentScrollLeft - scrollStep,
      behavior: "smooth",
    });
  };

  const scrollRightClick = () => {
    const currentScrollLeft = listRef?.current?.scrollLeft;
    const blockSize = listRef?.current?.offsetWidth;
    const scrollStep =
      size?.width > 1366
        ? listRef?.current?.offsetWidth / 4
        : listRef?.current?.offsetWidth / 2;
    listRef?.current?.scrollTo({
      top: 0,
      left: currentScrollLeft + scrollStep,
      behavior: "smooth",
    });
  };

  return (
    <>
      <InfoCardHorizontalList
        className="InfoCardHorizontalList"
        ref={listRef}
        onScroll={onScroll}
      >
        <CarouselWrapper style={{}} className="CarouselWrapper">
          {whoWeAres.map((card) => {
            return (
              <CarouselInfoCard key={card.name}>
                <InfoCardTitle>{card.name}</InfoCardTitle>
                <InfoCardSubtitle>{card.title}</InfoCardSubtitle>
                <InfoCardDescription>{card.description}</InfoCardDescription>
              </CarouselInfoCard>
            );
          })}
        </CarouselWrapper>
      </InfoCardHorizontalList>
      <CarouselButtonsWrapper>
        <ArrowLeftScroll $active={leftActive} onClick={scrollLeftClick} />
        <ArrowRightScroll $active={rightActive} onClick={scrollRightClick} />
      </CarouselButtonsWrapper>
    </>
  );
};

const ArrowLeftScroll = styled(ArrowLeft)`
  opacity: 0.3;
  cursor: pointer;
  padding: 20px 20px 20px 0;

  ${({ $active }) => {
    return $active
      ? `
      opacity: 1;
      fill: #4200FF;
      `
      : `
      fill: #47474F;
      `;
  }}
`;

const ArrowRightScroll = styled(ArrowRight)`
  opacity: 0.3;
  cursor: pointer;
  padding: 20px 0 20px 20px;

  ${({ $active }) => {
    return $active
      ? `
      opacity: 1;
      fill: #4200FF;
      `
      : `
      fill: #47474F;
      `;
  }}
`;

const InfoCardHorizontalList = styled.div`
  width: auto;
  overflow-y: auto;

  scrollbar-width: none;
  &::-webkit-scrollbar {
    display: none;
  }
`;

const CarouselWrapper = styled.div`
  display: flex;
  flex-direction: column;
  width: auto;
  ${media.m`
    display: block;
    width: ${(whoWeAres.length - 0) * 385}px;
    width: calc(calc( 100% / 2 ) * ${whoWeAres.length});
  `}

  ${media.l`
    display: block;
    width: ${(whoWeAres.length - 0) * 385}px;
    width: calc(calc( 100% / 4 ) * ${whoWeAres.length});
  `}
`;

const CarouselButtonsWrapper = styled.div`
  text-align: left;
  display: none;

  ${media.m`
    display: block;
  `}
`;

const CarouselInfoCard = styled.div`
  padding: 24px 24px 24px 0;

  ${media.m`
    width: calc(100% / ${whoWeAres.length});
    display: inline-block;
    vertical-align: top;
    box-sizing: border-box;
  `}

  ${media.l`
    /* width: 25%; */
    `}

    ${media.xl`
    `};
`;

